patch:
--- a/counter.v
+++ b/counter.v
@@ -1,12 +1,12 @@
 module counter_16bit(
   input clk,
   input rst_n,
   output reg [15:0] count
 );

-  always @(posedge clk)
+  always @(posedge clk or negedge rst_n)
   begin
     if (~rst_n)
       count <= 16'b0;
     else
       count <= count + 1;
   end

before_code:
module counter_16bit(
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk)
  begin
    if (~rst_n)
      count <= 16'b0;
    else
      count <= count + 1;
  end

endmodule

after_code:
module counter_16bit(
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk or negedge rst_n)
  begin
    if (~rst_n)
      count <= 16'b0;
    else
      count <= count + 1;
  end

endmodule
